"use strict";

//#region Game Class Def

class Player extends Entity{
    frog;
    score;
    lane;
    frogCatched;
    isGolden = false;
    dead = false;

    constructor(_model, _pos, _rot, _scl){
        super(_model, _pos, _rot, _scl);
        this.lane = 0;
        this.score = 0;
        this.frogCatched = false;
        this.frog = new Entity(frogModel, VMath.zeroV3(), Quat.fromEuler(0,Math.PI * 0.5,0), VMath.uniformV3(2));
        this.frog.visible = false;
    }

    //Render both the player and the frog
    render(drawQueue, sunLight, clipPlanes, viewMat, projX, projY){
        super.render(drawQueue, sunLight, clipPlanes, viewMat, projX, projY);
        this.frog.render(drawQueue, sunLight, clipPlanes, viewMat, projX, projY);
    }
}

class Projectile extends Entity{
    radius;
    velocity;
    renderIndex;
    frogIndex;
    isGolden = false;
    
    constructor(_model, _pos, _rot, _scl, _radius, _initalVelocity){
        super(_model, _pos, _rot, _scl);

        this.radius = _radius;
        this.velocity = _initalVelocity;
        this.renderIndex = 0;
        this.frogIndex = 0;
    }

    //Update and clamp projectile position every frame
    update(delta){
        if (!this.visible){
            return;
        }

        let vel = this.velocity;
        let translation = VMath.copy3D(vel);
        let pos = this.position;
        translation = VMath.multi3D(translation, delta);

        this.position = VMath.add3D(pos, translation);
        pos = this.position;

        let minX = -12.5 + this.radius;
        let maxX = 12.5 - this.radius;

        if (pos[0] <= minX || pos[0] >= maxX){
            vel[0] *= -1;
            this.rotation.rotateAlongLocalAxis([0,1,0], Math.PI);
        }

        pos[0] = VMath.clamp(pos[0], minX, maxX);
    }
}

