//Draw Frog UI
function drawFrogUI(x, y){
    ctx.strokeStyle = "black";

    ctx.lineWidth = 5;

    let eyeX = Math.cos(Math.PI * 3 / 4) * 25;
    let eyeY = Math.sin(Math.PI * 3 / 4) * 25;

    //Head outline
    ctx.fillStyle = "black";
    ctx.beginPath();
    ctx.arc(x, y, 30, 0, VMath.tau);

    ctx.arc(x + eyeX, y - eyeY, 17, 0, VMath.tau);

    ctx.arc(x - eyeX, y - eyeY, 17, 0, VMath.tau);
    ctx.fill();

    //Head
    ctx.fillStyle = "lime";
    ctx.beginPath();
    ctx.arc(x, y, 25, 0, VMath.tau);

    ctx.arc(x + eyeX, y - eyeY, 12, 0, VMath.tau);

    ctx.arc(x - eyeX, y - eyeY, 12, 0, VMath.tau);
    ctx.fill();

    //Eyes
    ctx.fillStyle = "yellow";
    ctx.beginPath();
    ctx.arc(x + eyeX, y - eyeY, 5, 0, VMath.tau);
    ctx.fill();
    ctx.beginPath();
    ctx.arc(x - eyeX, y - eyeY, 5, 0, VMath.tau);
    ctx.fill();

    //Mouth
    ctx.beginPath();
    ctx.moveTo(x - 10,  y + 7);
    ctx.lineTo(x, y - 3);
    ctx.lineTo(x + 10, y + 7);
    ctx.stroke();

    ctx.lineWidth = 0;
}

//Game UI Draw
function gameDrawUI(){
    ctx.lineWidth = 10;

    ctx.fillStyle = "white";
    ctx.strokeStyle = "black";
    ctx.beginPath();
    ctx.rect(0, 560, screenWidth, 240);
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.rect(0, 680, screenWidth, 120);
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.fillStyle = "black";
    ctx.fillText("Red Caught Frogs", 15, 585);

    for(let i = 0; i < redPlayer.score; i++){
        let x = 50 + i * 75;
        drawFrogUI(x, 635);
    }

    ctx.fillStyle = "black";
    ctx.fillText("Blue Caught Frogs", 15, 705);

    for(let i = 0; i < bluePlayer.score; i++){
        let x = 50 + i * 75;
        drawFrogUI(x, 755);
    }

    ctx.lineWidth = 0;

    if (redWin || blueWin){
        ctx.save();

        changeFontSize(100);

        ctx.translate(screenWidth * 0.5, screenHeight * 0.5);

        if (redWin && blueWin){
            ctx.fillStyle = "orange";
        }
        else{
            if (redWin){
                ctx.fillStyle = "red";
            }
            else{
                ctx.fillStyle = "blue";
            }
        }

        ctx.beginPath();
        ctx.rect(-screenWidth * 0.5, -185, screenWidth, 100);
        ctx.fill();

        ctx.beginPath();
        ctx.fillStyle = "white";
        if (redWin && blueWin){
            ctx.fillText("DRAW", -150, -100);
        }
        else{
            if (redWin){
                ctx.fillText("RED WINS", -240, -100);
            }
            else{
                ctx.fillText("BLUE WINS", -270, -100);
            }
        }

        ctx.restore();
    }
}

//Change difficulty to easy
function toEasyMode(){
    maxFrog = 3;
    minFrogSpeed = 5;
    maxFrogSpeed = 10;
    startingFrog = 1;
    document.getElementById("gameTitle").innerHTML = "Easy Frog Catching Game";

    resetGame();
}

//Change difficulty to normal
function toNormalMode(){
    maxFrog = 4;
    minFrogSpeed = 7.5;
    maxFrogSpeed = 15;
    startingFrog = 1;
    document.getElementById("gameTitle").innerHTML = "Normal Frog Catching Game";

    resetGame();
}

//Change difficulty to hard
function toHardMode(){
    maxFrog = 6;
    minFrogSpeed = 12.5;
    maxFrogSpeed = 25;
    startingFrog = 2;
    document.getElementById("gameTitle").innerHTML = "Hard Frog Catching Game";

    resetGame();
}

//function Reset Game State
function resetGame(){
    renderList = [];
    frogList = [];
    gameStop = false;
    stop = false;

    gameSetup();
}

//Add a Frog to the game
function addFrogAtLane(i){
    let lane = i * 2.25 - 9;
    let pos = [12.5, 0, lane];
    let velocity = [0,0,0];

    if (Math.random() > 0.5){
        pos[0] *= -1;
    }

    velocity[0] = VMath.randRange(minFrogSpeed, maxFrogSpeed);

    let isGoldenFrog = Math.random() <= goldenFrogSpawnChance;
        
    if (isGoldenFrog){
        velocity[0] = 50;
    }

    let rotDir = Math.PI * 0.5;
    if (Math.random() > 0.5){
        velocity[0] *= -1;
        rotDir *= -1;
    }

    let frog = new Projectile(frogModel, pos, Quat.fromEuler(0,rotDir,0), VMath.uniformV3(2), 1, velocity);
    if (isGoldenFrog){
        frog.isGolden = true;
        frog.model = goldenFrogModel;
    }

    frog.renderIndex = renderList.length;
    frog.frogIndex = frogList.length;
    
    renderList.push(frog);
    frogList.push(frog);

    laneState[i] = true;
}

//Remove frog from render and frog list
function removeFrog(frog){
    removeFrom(renderList, frog.renderIndex);
    removeFrom(frogList, frog.frogIndex);

    if (frog.frogIndex >= frogList.length){
        return;
    }

    let swapped = frogList[frog.frogIndex];

    swapped.renderIndex = frog.renderIndex;
    swapped.frogIndex = frog.frogIndex;
}

function updateFrogAmount(){
    let availableLane = [];
    for(let j = 0; j < 9; j++){
        if (redPlayer.lane != j && bluePlayer.lane != j && !laneState[j]){
            availableLane.push(j);
        }
    }

    for(let j = 0; j < availableLane.length - 1; j++){
        let randomIndex = VMath.randRangeInt(j, availableLane.length - 1);
        let randomItem = availableLane[randomIndex];
        availableLane[randomIndex] = availableLane[j];
        availableLane[j] = randomItem;
    }

    let totalScore = redPlayer.score + bluePlayer.score;

    if (redPlayer.frogCatched){
        if (redPlayer.isGolden){
            totalScore += 2;
        }
        else{
            totalScore++;
        }
    }
    if (bluePlayer.frogCatched){
        if (bluePlayer.isGolden){
            totalScore += 2;
        }
        else{
            totalScore++;
        }
    }

    let currentMaxFrog = Math.max(Math.floor((totalScore) / 2) + startingFrog, 1);
    currentMaxFrog = Math.min(currentMaxFrog, maxFrog);

    let newFrogAmount = Math.min(currentMaxFrog - frogList.length, availableLane.length);
    
    for(let j = 0; j < newFrogAmount; j++){
        addFrogAtLane(availableLane[j]);
    }
}

//Player catches the frog
function catchFrog(frog, targetPlayer){
    targetPlayer.isGolden = frog.isGolden;

    targetPlayer.frogCatched = true;
    removeFrog(frog);
    laneState[targetPlayer.lane] = false;

    updateFrogAmount();
}

//Detect and resolve Frog and player collision
function frogCollisionDetection(targetPlayer, playerForward){
    let playerRadius = 0.5;
    let catchPosition = VMath.add3D(VMath.multi3D(playerForward, 0.5), targetPlayer.position);

    for(let i = 0; i < frogList.length; i++){
        let frog = frogList[i];

        let dir = VMath.sub3D(frog.position, catchPosition);
        dir[1] = 0;
        
        if (VMath.length3D(dir) <= frog.radius + playerRadius){
            if (targetPlayer.frogCatched || VMath.dot3D(VMath.normal3D(frog.velocity), playerForward) >= 0){
                if (frog.isGolden){
                    removeFrog(frog);
                    laneState[targetPlayer.lane] = false;
                    updateFrogAmount();
                }
                else{
                    targetPlayer.dead = true;
                }
            }else{
                catchFrog(frog, targetPlayer);
            }
        }
    }
}

//Switch the goal from top to bottom or from bottom to top
function flipGoal(){
    if (goalLane >= 9){
        envObj.rotation = Quat.makeQuat([0,1,0], Math.PI);
        goalLane = -1;
    }else{
        envObj.rotation = Quat.identity();
        goalLane = 9;
    }
}

//Game Setup
function gameSetup(){
    renderList.push(envObj);
    for(let i = 0; i < playerList.length; i++){
        let player = playerList[i];
        renderList.push(player);
        player.frog.rotation.setEuler(0,Math.PI * 0.5,0);
        player.frog.visible = false;

        player.score = 0;
        player.frogCatched = false;
        player.lane = 4;
        player.dead = false;
        player.isGolden = false;

        player.rotation.setEuler(0, -Math.PI * 0.5, 0);
    }
    redPlayer.position = [-2, 0, 0];
    bluePlayer.position = [2, 0, 0];

    cam.position = [0, 23, -23];
    cam.rotation = Quat.fromEuler(60 * VMath.degToRad(), 0, 0);

    for(let i = 0; i < laneState.length; i++){
        laneState[i] = false;
    }

    updateFrogAmount();

    envObj.rotation = Quat.identity();
    goalLane = 9;
    redWin = false;
    blueWin = false;
}

//Check Game state
function updateGameState(){
    let gameDesc = document.getElementById("desc");

    if ((redPlayer.score >= winningScore && bluePlayer.score >= winningScore) ||
        (redPlayer.dead && bluePlayer.dead)){
        gameStop = true;
        redWin = true;
        blueWin = true;
        gameDesc.innerHTML = "Draw";
    }
    else{
        let camForward = VMath.matforward(cam.rotation.toMatrix());
        camForward = VMath.multi3D(camForward, 5);
        if (redPlayer.score >= winningScore || bluePlayer.dead){
            gameStop = true;
            redWin = true;
            cam.position = VMath.add3D(cam.position, redPlayer.position);
            cam.position = VMath.add3D(cam.position, camForward);
            gameDesc.innerHTML = "Congrate Red, you win";
        }
        else if (bluePlayer.score >= winningScore || redPlayer.dead){
            gameStop = true;
            blueWin = true;
            cam.position = VMath.add3D(cam.position, bluePlayer.position);
            cam.position = VMath.add3D(cam.position, camForward);
            gameDesc.innerHTML = "Congrate Blue, you win";
        }
        else{
            if (redPlayer.score >= 9 && bluePlayer.score >= 9){
                gameDesc.innerHTML = "Red and Blue both need one more frog to win";
            }
            else{
                if (redPlayer.score >= 9){
                    gameDesc.innerHTML = "Red needs one more frog to win";
                }
                else if (bluePlayer.score >= 9){
                    gameDesc.innerHTML = "Blue needs one more frog to win";
                }
                else{
                    gameDesc.innerHTML = "First to catch 10 frogs wins";
                }
            }
        }
    }
}

//Game Update function
function gameUpdate(delta){

    if (gameStop){
        let rad = Math.PI * 0.1 * delta;
        let camPos = cam.position;
        
        let offset = VMath.zeroV3();

        if (redWin != blueWin){
            if (redWin){
                offset = redPlayer.position;
            }else{
                offset = bluePlayer.position;
            }
        }

        camPos = VMath.sub3D(camPos, offset);
        camPos = Quat.rotateVecAlongAxis([0,1,0], rad, camPos);
        cam.position = VMath.add3D(camPos, offset);

        cam.rotation.rotateAlongWorldAxis([0,1,0], rad);
        return;
    }

    for(let i = 0; i < frogList.length; i++){
        frogList[i].update(delta);
    }

    let redZPos = redPlayer.position[2];
    let blueZPos = bluePlayer.position[2];

    //Red Control
    if (isPressed("w")){
        redZPos += 2.25;
        redPlayer.lane++;
    }
    if (isPressed("s")){
        redZPos -= 2.25;
        redPlayer.lane--;
    }
    if (isPressed("a")){
        redPlayer.rotation.setEuler(0, Math.PI * -0.5, 0);
        redPlayer.frog.rotation.setEuler(0, Math.PI * 0.5, 0);
    }
    if (isPressed("d")){
        redPlayer.rotation.setEuler(0, Math.PI * 0.5, 0);
        redPlayer.frog.rotation.setEuler(0, Math.PI * -0.5, 0);
    }

    //Blue Control
    if (isPressed("i")){
        blueZPos += 2.25;
        bluePlayer.lane++;
    }
    if (isPressed("k")){
        blueZPos -= 2.25;
        bluePlayer.lane--;
    }
    if (isPressed("j")){
        bluePlayer.rotation.setEuler(0, Math.PI * -0.5, 0);
        bluePlayer.frog.rotation.setEuler(0, Math.PI * 0.5, 0);
    }
    if (isPressed("l")){
        bluePlayer.rotation.setEuler(0, Math.PI * 0.5, 0);
        bluePlayer.frog.rotation.setEuler(0, Math.PI * -0.5, 0);
    }

    redZPos = VMath.clamp(redZPos, -11.25, 11.25);
    blueZPos = VMath.clamp(blueZPos, -11.25, 11.25);
    redPlayer.lane = VMath.clamp(redPlayer.lane, -1, 9);
    bluePlayer.lane = VMath.clamp(bluePlayer.lane, -1, 9);

    redPlayer.position[2] = redZPos;
    bluePlayer.position[2] = blueZPos;

    for(let i = 0; i < playerList.length; i++){
        let player = playerList[i];

        let playerForward = VMath.matforward(player.rotation.toMatrix());

        if (player.frogCatched && player.lane == goalLane){
            player.frogCatched = false;
            if (player.isGolden){
                player.score += 2;
            }
            else{
                player.score++;
            }
            player.isGolden = false;
            flipGoal();
        }
    
        frogCollisionDetection(player, playerForward);

        if (player.frogCatched){
            if (player.isGolden){
                player.frog.model = goldenFrogModel;
            }
            else{
                player.frog.model = frogModel;
            }

            player.frog.visible = true;
            player.frog.position = VMath.add3D(player.position, playerForward);
            player.frog.position[1] = 2.5;
        }else{
            player.frog.visible = false;
        }
    }

    updateGameState();
}

